var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_NULL","text":{"KOREA":"나는...... 이제 존재하지 않아.","JPN":"私は……もう存在しない。","ENG":"I... don't exist anymore.","TWN":"我……現在不存在了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_NULL","text":{"KOREA":"지금의 나는 그저...... 예전의 내가 남기고 간 흔적일 뿐이니까......","JPN":"今の私はただ……昔の私が残した痕跡にすぎないから……","ENG":"I'm just… a vestige of what I once was…","TWN":"現在的我只不過是…之前的我所殘留下的痕跡……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_NULL","text":{"KOREA":"하나씩, 하나씩...... 상처를 꿰맬 때마다 내 안에서 따뜻한 것들이 빠져 나가......","JPN":"一つずつ、一つずつ……傷を負うたびに私の中から温かいものが抜けていく……","ENG":"One by one… warm things slip away with each stitch of the wound…","TWN":"一個，一個……每當縫合傷口時，我內心溫暖的東西就會一個一個的流失……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_NULL","text":{"KOREA":"이젠 그것들이 뭐였는지도 떠올릴 수 없지만......","JPN":"もう、それが何だったのかすら思い出せなくなってきたけど……","ENG":"I can't even recall what they are…","TWN":"現在連那些是什麼都想不起來了……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_NULL","text":{"KOREA":"예전의 내가 좋아했던 따뜻함만큼은...... 항상 그리워하던 온기만큼은 잊지 않았어.","JPN":"かつて私が好きだった温もりだけは……いつも懐かしく思ってた温もりだけは忘れてない。","ENG":"But I have not forgotten the warmth that I once held dear… the warmth that I always longed for.","TWN":"過去我所喜歡的溫暖，我從來沒有忘記，而且一直思念的那個溫暖。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_NULL","text":{"KOREA":"......집.","JPN":"……家。","ENG":"… Home.","TWN":"……家。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_NULL","text":{"KOREA":"예전의 나는...... 집에 가고 싶었던 것 같아.","JPN":"昔の私は……家に行きたかったのかもしれない。","ENG":"I think the old me… wanted to go home.","TWN":"以前的我……好像很想回家。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_NULL","text":{"KOREA":"자주 다투기도 하고, 무서울 때도 있는 사람들이지만, 따뜻함이 느껴졌던......","JPN":"よく喧嘩したり、怖い時もあったけど、温もりが感じられた……","ENG":"We argued a lot, and sometimes they were scary… but they were warm…","TWN":"雖然他們經常吵架，我也有害怕的時候，但能感覺到溫暖……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_NULL","text":{"KOREA":"그런 집.","JPN":"そんな家。","ENG":"That's the home I longed for.","TWN":"那樣的家。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_NULL","text":{"KOREA":"하지만 아무리 해도 돌아갈 수 없어......","JPN":"でも、どうしても帰れない……","ENG":"But I can no longer go back, no matter how hard I try…","TWN":"但無論如何都回不去了……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_NULL","text":{"KOREA":"이런 손으로는...... 잠긴 문을 열 수 없으니까......","JPN":"こんな手じゃ……ドアを開けることができないから……","ENG":"With these hands… I can't open the locked door…","TWN":"這樣的手……沒辦法打開鎖著的門……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_NULL","text":{"KOREA":"그러니까...... 여기가 지금의 내...... 새로운 집이면 좋겠어......","JPN":"だから……ここが今の私の……新しい家だといいな……","ENG":"So... I hope this place can become my… new home…","TWN":"所以……就當這裡是我的新家……就好了……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_NULL","text":{"KOREA":"그래도...... 괜찮아?","JPN":"それでも……いい？","ENG":"Is that… okay with you?","TWN":"那樣……也沒關係嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};